function useToggle(initialValue = false) {
  if (initialValue) {
    const [value, setValue] = useState(true);
    return [value, () => setValue(prev => !prev)];
  }
  const [value, setValue] = useState(false);
  return [value, () => setValue(prev => !prev)];
}

